276	// apply_state writes all architectural state fields to the gdbstub session.
277	// Templated on Session so tests can inject a recording stub without a real
278	// TCP socket (duck-type: needs send_command(string_view)->string).
279	template<class Session>
280	inline void apply_state(Session& sess,
281	                        const gdbstub::RegMap& reg_map,
282	                        const hybrid_state_v1& state)
283	{
284	  // RV64 core: x0..x31 = 0..31, pc = 32. Hard-coded because the core
285	  // feature is always first.
286	  for (unsigned i = 1; i < 32; ++i) {
287	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
288	    if (reply != "OK")
289	      throw std::runtime_error(
290	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
291	  }
292	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
293	  if (reply != "OK")
294	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
295	
296	  if ((state.flags & HYBRID_FLAG_FP) != 0u)
297	    for (std::size_t i = 0; i < 32; ++i)
298	      try_write_named_u64(sess, reg_map, hybrid_fpr_names[i], state.fpr[i]);
299	
300	  for (const auto& slot : kCsrByName)
301	    try_write_named_u64(sess, reg_map, slot.first, state.*(slot.second));
302	
303	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
304	    try_write_named_u64(sess, reg_map, "pmpcfg" + std::to_string(i),
305	                        state.pmpcfg[i]);
306	  for (uint16_t i = 0; i < HYBRID_PMP_ADDR_NUM; ++i)
307	    try_write_named_u64(sess, reg_map, "pmpaddr" + std::to_string(i),
308	                        state.pmpaddr[i]);
309	
310	  if ((state.flags & HYBRID_FLAG_V) != 0u && state.vlenb > 0u
311	      && state.vlenb <= HYBRID_VLEN_BYTES_MAX) {
312	    try_write_named_u64(sess, reg_map, "vstart", state.vstart);
313	    try_write_named_u64(sess, reg_map, "vxsat",  state.vxsat);
314	    try_write_named_u64(sess, reg_map, "vxrm",   state.vxrm);
315	    try_write_named_u64(sess, reg_map, "vcsr",   state.vcsr);
316	    try_write_named_u64(sess, reg_map, "vtype",  state.vtype);
317	    try_write_named_u64(sess, reg_map, "vl",     state.vl);
318	    const std::size_t vbytes = static_cast<std::size_t>(state.vlenb);
319	    for (uint16_t i = 0; i < 32; ++i) {
320	      const std::string name = "v" + std::to_string(i);
321	      try_write_named_bytes(
322	        sess, reg_map, name,
323	        &state.vreg[static_cast<std::size_t>(i) * HYBRID_VLEN_BYTES_MAX],
324	        vbytes);
325	    }
326	  }
327	}
