331	// Restores x1..x31, PC, FPR (if HYBRID_FLAG_FP), M-mode CSRs, PMP, and
332	// vector data regs (if HYBRID_FLAG_V) into the QEMU vCPU via the gdbstub
333	// at `port`, then continues. Caller is responsible for waitpid().
334	inline void restore_state_via_gdbstub(uint16_t port,
335	                                      const hybrid_state_v1& state,
336	                                      pid_t child_pid = -1)
337	{
338	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
339	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
340	                                          child_pid);
341	  spdlog::info("hybrid handback: connected, discovering register map");
342	  gdbstub::Session sess{fd};
343	
344	  const auto reg_map = detail::discover_reg_map(sess);
345	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
346	               reg_map.size());
347	
348	  detail::apply_state(sess, reg_map, state);
349	
350	  spdlog::info("hybrid handback: continuing target");
351	  sess.cont();
352	}
