354	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
355	// status (or 128 + signal for abnormal termination).
356	inline auto run_qemu_handback(const std::string& qemu_binary,
357	                              const std::string& elf_path,
358	                              const hybrid_state_v1& state,
359	                              const std::string& shared_mem_path = {},
360	                              uint64_t shared_mem_size = 0) -> int
361	{
362	  const auto port = detail::pick_free_port();
363	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
364	               qemu_binary, port);
365	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
366	                                       shared_mem_path, shared_mem_size);
367	
368	  try {
369	    restore_state_via_gdbstub(port, state, pid);
370	  } catch (const detail::ChildExitedDuringConnect& d) {
371	    return d.status;
372	  } catch (...) {
373	    ::kill(pid, SIGKILL);
374	    int wstat = 0;
375	    ::waitpid(pid, &wstat, 0);
376	    throw;
377	  }
378	
379	  int wstat = 0;
380	  if (::waitpid(pid, &wstat, 0) < 0)
381	    throw std::runtime_error(std::string{"waitpid: "}
382	                             + std::strerror(errno));
383	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
384	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
385	  return -1;
386	}
